#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
TreeNode* build_tree(int* nums, int index, int n) {
    if (index >= n || nums[index] == -1) {
        return NULL;
    }
    TreeNode* node = new TreeNode(nums[index]);
    node->left = build_tree(nums, 2 * index + 1, n);
    node->right = build_tree(nums, 2 * index + 2, n);
    return node;
}
void inorder_traversal(TreeNode* root) {
    if (root) {
        inorder_traversal(root->left);
        cout << root->val << endl;
        inorder_traversal(root->right);
    }
}
